    17→// Prevent direct access
    18→if (!defined('ABSPATH')) {
    19→    exit;
    20→}
    21→
    22→// Define plugin constants
    23→define('AGENTPRESS_VERSION', '1.0.0');
    24→define('AGENTPRESS_PLUGIN_DIR', plugin_dir_path(__FILE__));
    25→define('AGENTPRESS_PLUGIN_URL', plugin_dir_url(__FILE__));
