    52→/**
    53→ * Register custom post types for capabilities and logs.
    54→ */
    55→function agentpress_register_cpts() {
    56→    // Register agentpress_capability CPT
    57→    register_post_type('agentpress_capability', array(
    58→        'labels' => array(
    59→            'name' => __('AgentPress Capabilities', 'agentpress'),
